        ScriptedInput scriptedInput = new ScriptedInput(keycodes);
        WalkerGame game = new WalkerGame(scriptedInput);

        HeadlessApplicationConfiguration config = new HeadlessApplicationConfiguration();
        // 60 updates/s keeps CPU usage reasonable while staying snappy.
        config.updatesPerSecond = 60;

        // Boot the headless application. HeadlessApplication constructs a
        // default MockInput and assigns it to Gdx.input inside its constructor.
        HeadlessApplication app = new HeadlessApplication(game, config);

        // Overwrite Gdx.input with our scripted subclass so that the rest of
        // the framework (and WalkerGame.create()) sees it.
        // NOTE: WalkerGame.create() runs on the headless thread during the
        // HeadlessApplication constructor, so we must set Gdx.input BEFORE
        // the constructor returns -- but that is not possible through the
        // public API. Instead we post a runnable that swaps it in before the
        // first render() call.
        Gdx.app.postRunnable(() -> Gdx.input = scriptedInput);

        // HeadlessApplication.mainLoopThread is a protected field. We access
        // it via reflection so we can join it and prevent the JVM from
        // exiting before the simulation finishes.
        Thread mainLoopThread = getMainLoopThread(app);
        if (mainLoopThread != null) {
            mainLoopThread.join();
        }
    }

    /**
     * Retrieves the protected mainLoopThread field from HeadlessApplication.
     */
    private static Thread getMainLoopThread(HeadlessApplication app) {
        try {
            Field field = HeadlessApplication.class.getDeclaredField("mainLoopThread");
            field.setAccessible(true);
            return (Thread) field.get(app);
        } catch (Exception e) {
            System.err.println("Warning: could not access mainLoopThread: " + e.getMessage());
            return null;
        }
    }

    /**
     * Reads and validates the replay file, returning a list of
     * com.badlogic.gdx.Input.Keys constants.
     *
     * Blank lines and lines starting with '#' are silently skipped.
     * Any unrecognised token causes the program to exit with a non-zero status.
     */
    private static List<Integer> parseReplayFile(String path) throws IOException {
        List<Integer> keycodes = new ArrayList<>();

        try (BufferedReader reader = new BufferedReader(
                new FileReader(path, StandardCharsets.UTF_8))) {
            String line;
            while ((line = reader.readLine()) != null) {
                String trimmed = line.trim();
                if (trimmed.isEmpty() || trimmed.startsWith("#")) {
                    continue; // skip blank lines and comments
                }

                String upper = trimmed.toUpperCase();
                switch (upper) {
                    case "UP":    keycodes.add(Input.Keys.UP);    break;
                    case "DOWN":  keycodes.add(Input.Keys.DOWN);  break;
                    case "LEFT":  keycodes.add(Input.Keys.LEFT);  break;
                    case "RIGHT": keycodes.add(Input.Keys.RIGHT); break;
                    default:
                        System.err.println("Error: unknown key " + trimmed);
                        System.exit(1);
                }
            }
        }

        return keycodes;
    }
}

